import numpy as np

def is_bounded(subset, metric='euclidean'):
    if not subset:
        return True  # Empty set is trivially bounded

    if metric == 'euclidean':
        points = np.array(subset)
        distances = np.linalg.norm(points[:, np.newaxis] - points, axis=2)
        max_distance = np.max(distances)
        return np.isfinite(max_distance)
    else:
        raise ValueError("Unsupported metric")

# Example usage:
subset = [(1, 2), (3, 4), (5, 6)]
print(is_bounded(subset))  # Output: True
